// with order fields injected as a single 'order' object, and returns the resulting discount amount.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Create a JavaScript object from the order map and set it as 'order' variable
	jsOrder := vm.NewObject()
	for key, value := range order {
		if err := jsOrder.Set(key, value); err != nil {
			return 0.0, fmt.Errorf("failed to set order field %s: %w", key, err)
		}
	}
	if err := vm.Set("order", jsOrder); err != nil {
		return 0.0, fmt.Errorf("failed to set order object: %w", err)
	}

	// Set up timeout mechanism
	timeout := time.AfterFunc(5*time.Second, func() {
		vm.Interrupt("script execution timeout")
	})
	defer timeout.Stop()

	// Execute the script
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	discount, ok := result.Export().(float64)
	if !ok {
		// Try to convert from other numeric types
		switch v := result.Export().(type) {
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
		}
	}

	// Validate discount is within reasonable bounds
	if discount < 0 {
		return 0.0, fmt.Errorf("discount cannot be negative: %f", discount)
	}

	return discount, nil
}

